window.BILARA["dn17"] = window.BILARA["dn17"] || {};
window.BILARA["dn17"]["vi"] = {
  "dn17:0.1": "Trường Bộ Kinh 17 ",
  "dn17:0.2": "Kinh Đại Thiện Kiến ",
  "dn17:1.1.1": "Như vầy tôi nghe",
  "dn17:1.1.2": "Một thời Thế Tôn trú tại Kusinārā, trong rừng Sāla của họ Mallā ở Upavattana, giữa hai cây sāla song thọ, vào lúc nhập Niết-bàn. ",
  "dn17:1.2.1": "Rồi Tôn giả Ānanda đi đến chỗ Thế Tôn; sau khi đến, ông đảnh lễ Thế Tôn rồi ngồi xuống một bên. Ngồi xuống một bên, Tôn giả Ānanda bạch Thế Tôn rằng: ",
  "dn17:1.2.2": "“Bạch Thế Tôn, xin Thế Tôn chớ nhập Niết-bàn tại thị trấn nhỏ bé này, thị trấn hoang vu này, thị trấn chi nhánh này. ",
  "dn17:1.2.3": "Bạch Thế Tôn, có những thành phố lớn khác. ",
  "dn17:1.2.4": "Đó là—Campā, Rājagaha, Sāvatthi, Sāketa, Kosambī, Bārāṇasī; ",
  "dn17:1.2.5": "xin Thế Tôn hãy nhập Niết-bàn ở đó. ",
  "dn17:1.2.6": "Ở đó có nhiều đại Sát-đế-lỵ, đại Bà-la-môn, đại gia chủ có lòng tin đối với Như Lai, họ sẽ cử hành lễ cúng dường nhục thân Như Lai.” ",
  "dn17:1.3.1": "“Chớ nói như vậy, này Ānanda; chớ nói như vậy, này Ānanda rằng: ",
  "dn17:1.3.2": "‘thị trấn nhỏ bé, thị trấn hoang vu, thị trấn chi nhánh.’ ",
  "dn17:1.3.3.0": "1. Kinh đô Kusāvatī ",
  "dn17:1.3.4": "Này Ānanda, thuở xưa có vị vua tên là Mahāsudassana thuộc dòng Sát-đế-lỵ, đã làm lễ quán đảnh, bốn phương chiến thắng, đất nước an ổn. ",
  "dn17:1.3.5": "Này Ānanda, Kusinārā này chính là kinh đô Kusāvatī của vua Mahāsudassana. ",
  "dn17:1.3.6": "Từ đông sang tây dài mười hai do-tuần, từ bắc xuống nam rộng bảy do-tuần. ",
  "dn17:1.3.7": "Này Ānanda, kinh đô Kusāvatī thịnh vượng, phồn vinh, đông dân cư, đầy người và dồi dào vật thực. ",
  "dn17:1.3.8": "Ví như, này Ānanda, kinh đô của chư thiên tên là Āḷakamandā thịnh vượng, phồn vinh, đông dân cư, đầy các dạ-xoa và dồi dào vật thực; ",
  "dn17:1.3.9": "cũng vậy, này Ānanda, kinh đô Kusāvatī thịnh vượng, phồn vinh, đông dân cư, đầy người và dồi dào vật thực. ",
  "dn17:1.3.10": "Này Ānanda, kinh đô Kusāvatī không khi nào vắng mười loại âm thanh cả ngày lẫn đêm, đó là—",
  "dn17:1.3.11": "tiếng voi, tiếng ngựa, tiếng xe, tiếng trống, tiếng trống cơm, tiếng đàn tỳ bà, tiếng hát, tiếng tù và, tiếng chiêng, tiếng vỗ tay, và âm thanh thứ mười là ‘Hãy ăn, hãy uống, hãy nhai’. ",
  "dn17:1.4.1": "Này Ānanda, kinh đô Kusāvatī được bao quanh bởi bảy vòng tường thành. ",
  "dn17:1.4.2": "Một vòng bằng vàng, một vòng bằng bạc, một vòng bằng ngọc lưu ly, một vòng bằng pha lê, một vòng bằng ngọc đỏ, một vòng bằng ngọc mắt mèo, một vòng bằng tất cả các loại báu. ",
  "dn17:1.5.1": "Này Ānanda, kinh đô Kusāvatī có bốn loại cổng bốn màu. ",
  "dn17:1.5.2": "Một cổng bằng vàng, một cổng bằng bạc, một cổng bằng ngọc lưu ly, một cổng bằng pha lê. ",
  "dn17:1.5.3": "Tại mỗi cổng có bảy cây cột được cắm sâu, mỗi cây sâu ba tầm người, cao mười hai tầm người. ",
  "dn17:1.5.4": "Một cột bằng vàng, một cột bằng bạc, một cột bằng ngọc lưu ly, một cột bằng pha lê, một cột bằng ngọc đỏ, một cột bằng ngọc mắt mèo, một cột bằng tất cả các loại báu. ",
  "dn17:1.6.1": "Này Ānanda, kinh đô Kusāvatī được bao quanh bởi bảy hàng cây tāla. ",
  "dn17:1.6.2": "Một hàng bằng vàng, một hàng bằng bạc, một hàng bằng ngọc lưu ly, một hàng bằng pha lê, một hàng bằng ngọc đỏ, một hàng bằng ngọc mắt mèo, một hàng bằng tất cả các loại báu. ",
  "dn17:1.6.3": "Cây tāla bằng vàng có thân bằng vàng, lá và trái bằng bạc. ",
  "dn17:1.6.4": "Cây tāla bằng bạc có thân bằng bạc, lá và trái bằng vàng. ",
  "dn17:1.6.5": "Cây tāla bằng ngọc lưu ly có thân bằng ngọc lưu ly, lá và trái bằng pha lê. ",
  "dn17:1.6.6": "Cây tāla bằng pha lê có thân bằng pha lê, lá và trái bằng ngọc lưu ly. ",
  "dn17:1.6.7": "Cây tāla bằng ngọc đỏ có thân bằng ngọc đỏ, lá và trái bằng ngọc mắt mèo. ",
  "dn17:1.6.8": "Cây tāla bằng ngọc mắt mèo có thân bằng ngọc mắt mèo, lá và trái bằng ngọc đỏ. ",
  "dn17:1.6.9": "Cây tāla bằng tất cả các loại báu có thân bằng tất cả các loại báu, lá và trái cũng bằng tất cả các loại báu. ",
  "dn17:1.6.10": "Này Ānanda, khi các hàng cây tāla ấy bị gió lay động, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc. ",
  "dn17:1.6.11": "Ví như, này Ānanda, một bản nhạc có năm loại nhạc cụ, được khéo tập dượt, khéo đánh nhịp, được các nhạc công thiện nghệ cùng biểu diễn, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc; ",
  "dn17:1.6.12": "cũng vậy, này Ānanda, khi các hàng cây tāla ấy bị gió lay động, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc. ",
  "dn17:1.6.13": "Này Ānanda, vào lúc bấy giờ, những kẻ ăn chơi, phóng túng, nghiện ngập trong kinh đô Kusāvatī, đã thưởng thức âm thanh của các hàng cây tāla ấy khi bị gió lay động. ",
  "dn17:1.7.0.1": "2. Đầy đủ bảy báu ",
  "dn17:1.7.0.2": "2.1. Xe báu ",
  "dn17:1.7.1": "Này Ānanda, vua Mahāsudassana đầy đủ bảy báu và bốn thần lực. ",
  "dn17:1.7.2": "Bảy báu ấy là gì? ",
  "dn17:1.7.3": "Này Ānanda, ở đây vào ngày Bố-tát rằm, sau khi tắm gội sạch sẽ và giữ giới Bố-tát, vua Mahāsudassana đang ngồi trên lầu cao của cung điện, ",
  "dn17:1.7.4": "thì xe báu cõi trời hiện ra với một ngàn căm, có vành, có trục, đầy đủ mọi đặc tính. ",
  "dn17:1.7.5": "Thấy vậy, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:1.7.6": "‘Ta có nghe rằng: “Vị Sát-đế-lỵ đã làm lễ quán đảnh, vào ngày Bố-tát rằm, sau khi tắm gội sạch sẽ và giữ giới Bố-tát, đang ngồi trên lầu cao của cung điện, mà thấy xe báu cõi trời hiện ra với một ngàn căm, có vành, có trục, đầy đủ mọi đặc tính, thì vị ấy sẽ trở thành Chuyển Luân Thánh Vương.” ",
  "dn17:1.7.7": "Vậy ta sẽ là Chuyển Luân Thánh Vương chăng?’ ",
  "dn17:1.8.1": "Rồi này Ānanda, vua Mahāsudassana đứng dậy khỏi chỗ ngồi, vắt y thượng lên một vai, tay trái cầm bình nước vàng, tay phải rảy nước lên xe báu và nói: ",
  "dn17:1.8.2": "‘Xe báu hãy lăn, xe báu hãy chinh phục.’ ",
  "dn17:1.8.3": "Rồi xe báu ấy, này Ānanda, lăn về hướng đông, vua Mahāsudassana cùng bốn loại quân đi theo. Này Ānanda, ở nơi nào xe báu dừng lại, vua Mahāsudassana cùng bốn loại quân đến cư trú ở đó. ",
  "dn17:1.9.1": "Này Ānanda, các vua chư hầu ở hướng đông đi đến gặp vua Mahāsudassana và thưa rằng: ",
  "dn17:1.9.2": "‘Xin đón chào đại vương, đại vương được hoan nghênh, tất cả là của đại vương, xin đại vương hãy chỉ bảo.’ ",
  "dn17:1.9.3": "Vua Mahāsudassana nói: ",
  "dn17:1.9.4": "‘Không được sát sinh, không được lấy của không cho, không được tà hạnh trong các dục, không được nói dối, không được uống rượu, và hãy sống theo lối hiện có.’ ",
  "dn17:1.9.5": "Này Ānanda, các vua chư hầu ở hướng đông đều trở thành chư hầu của vua Mahāsudassana. ",
  "dn17:1.10.1": "Rồi này Ānanda, xe báu ấy, sau khi lặn xuống biển đông rồi trồi lên, lại lăn về hướng nam …(v.v.)… ",
  "dn17:1.10.2": "sau khi lặn xuống biển nam rồi trồi lên, lại lăn về hướng tây …(v.v.)… ",
  "dn17:1.10.3": "sau khi lặn xuống biển tây rồi trồi lên, lại lăn về hướng bắc, vua Mahāsudassana cùng bốn loại quân đi theo. ",
  "dn17:1.10.4": "Này Ānanda, ở nơi nào xe báu dừng lại, vua Mahāsudassana cùng bốn loại quân đến cư trú ở đó. ",
  "dn17:1.10.5": "Này Ānanda, các vua chư hầu ở hướng bắc đi đến gặp vua Mahāsudassana và thưa rằng: ",
  "dn17:1.10.6": "‘Xin đón chào đại vương, đại vương được hoan nghênh, tất cả là của đại vương, xin đại vương hãy chỉ bảo.’ ",
  "dn17:1.10.7": "Vua Mahāsudassana nói: ",
  "dn17:1.10.8": "‘Không được sát sinh, không được lấy của không cho, không được tà hạnh trong các dục, không được nói dối, không được uống rượu, và hãy sống theo lối hiện có.’ ",
  "dn17:1.10.9": "Này Ānanda, các vua chư hầu ở hướng bắc đều trở thành chư hầu của vua Mahāsudassana. ",
  "dn17:1.11.1": "Rồi này Ānanda, xe báu ấy, sau khi đã chinh phục trái đất đến tận bờ biển, trở về kinh đô Kusāvatī, dừng lại như được gắn chặt ở trước cổng nội cung, nơi xét xử của vua Mahāsudassana, làm rực rỡ nội cung của vua Mahāsudassana. ",
  "dn17:1.11.2": "Này Ānanda, vua Mahāsudassana đã có một xe báu như vậy. ",
  "dn17:1.12.0": "2.2. Voi báu ",
  "dn17:1.12.1": "Lại nữa, này Ānanda, vua Mahāsudassana có một voi báu hiện ra, ",
  "dn17:1.12.2": "toàn thân trắng, đứng vững bảy chỗ, có thần lực, bay được trên không, là tượng vương tên Uposatha. ",
  "dn17:1.12.3": "Thấy vậy, tâm vua Mahāsudassana hoan hỷ: ",
  "dn17:1.12.4": "‘Thật tuyệt vời là voi này, nếu được huấn luyện thì sẽ rất tốt.’ ",
  "dn17:1.12.5": "Rồi này Ānanda, voi báu ấy—ví như loài voi hương thuần chủng đã được huấn luyện lâu ngày; cũng vậy—được huấn luyện ngay. ",
  "dn17:1.12.6": "Thuở xưa, này Ānanda, để thử voi báu ấy, vua Mahāsudassana đã cưỡi nó vào buổi sáng, đi khắp trái đất đến tận bờ biển, rồi trở về kinh đô Kusāvatī kịp dùng bữa sáng. ",
  "dn17:1.12.7": "Này Ānanda, vua Mahāsudassana đã có một voi báu như vậy. ",
  "dn17:1.13.0": "2.3. Ngựa báu ",
  "dn17:1.13.1": "Lại nữa, này Ānanda, vua Mahāsudassana có một ngựa báu hiện ra, ",
  "dn17:1.13.2": "toàn thân trắng, đầu đen, bờm như cỏ muñja, có thần lực, bay được trên không, là mã vương tên Valāhaka. ",
  "dn17:1.13.3": "Thấy vậy, tâm vua Mahāsudassana hoan hỷ: ",
  "dn17:1.13.4": "‘Thật tuyệt vời là ngựa này, nếu được huấn luyện thì sẽ rất tốt.’ ",
  "dn17:1.13.5": "Rồi này Ānanda, ngựa báu ấy, ví như loài ngựa thuần chủng đã được huấn luyện lâu ngày; cũng vậy—được huấn luyện ngay. ",
  "dn17:1.13.6": "Thuở xưa, này Ānanda, để thử ngựa báu ấy, vua Mahāsudassana đã cưỡi nó vào buổi sáng, đi khắp trái đất đến tận bờ biển, rồi trở về kinh đô Kusāvatī kịp dùng bữa sáng. ",
  "dn17:1.13.7": "Này Ānanda, vua Mahāsudassana đã có một ngựa báu như vậy. ",
  "dn17:1.14.0": "2.4. Ngọc báu ",
  "dn17:1.14.1": "Lại nữa, này Ānanda, vua Mahāsudassana có một ngọc báu hiện ra. ",
  "dn17:1.14.2": "Đó là viên ngọc lưu ly xinh đẹp, thuộc loại thượng hạng, có tám mặt, khéo mài giũa, trong suốt, sáng tỏ, không tì vết, đầy đủ mọi đặc tính. ",
  "dn17:1.14.3": "Này Ānanda, hào quang của ngọc báu ấy tỏa ra một do-tuần xung quanh. ",
  "dn17:1.14.4": "Thuở xưa, này Ānanda, để thử ngọc báu ấy, vua Mahāsudassana đã chỉnh đốn bốn loại quân, gắn viên ngọc lên đỉnh cờ rồi đi trong đêm tối mịt mù. ",
  "dn17:1.14.5": "Này Ānanda, các làng xung quanh, nhờ ánh sáng ấy mà bắt tay vào công việc, tưởng là ban ngày. ",
  "dn17:1.14.6": "Này Ānanda, vua Mahāsudassana đã có một ngọc báu như vậy. ",
  "dn17:1.15.0": "2.5. Nữ báu ",
  "dn17:1.15.1": "Lại nữa, này Ānanda, vua Mahāsudassana có một nữ báu hiện ra, ",
  "dn17:1.15.2": "đẹp đẽ, dễ nhìn, khả ái, có dung sắc cao quý tuyệt hảo, không quá cao, không quá thấp, không quá gầy, không quá mập, không quá đen, không quá trắng, vượt qua dung sắc phàm nhân nhưng chưa đạt đến dung sắc thiên nữ. ",
  "dn17:1.15.3": "Này Ānanda, sự đụng chạm của thân nữ báu ấy như đụng chạm vào bông gòn hay bông vải. ",
  "dn17:1.15.4": "Này Ānanda, khi trời lạnh thì thân nữ báu ấy ấm, khi trời nóng thì mát. ",
  "dn17:1.15.5": "Này Ānanda, từ thân nữ báu ấy tỏa ra mùi hương chiên-đàn, từ miệng tỏa ra mùi hương sen. ",
  "dn17:1.15.6": "Này Ānanda, nữ báu ấy đối với vua Mahāsudassana, dậy sớm hơn vua, đi ngủ muộn hơn vua, làm mọi việc đều tùy ý vua, hành xử dễ mến, nói lời khả ái. ",
  "dn17:1.15.7": "Này Ānanda, nữ báu ấy đối với vua Mahāsudassana, ngay cả trong ý cũng không bất trung, huống gì trong thân. ",
  "dn17:1.15.8": "Này Ānanda, vua Mahāsudassana đã có một nữ báu như vậy. ",
  "dn17:1.16.0": "2.6. Gia chủ báu ",
  "dn17:1.16.1": "Lại nữa, này Ānanda, vua Mahāsudassana có một gia chủ báu hiện ra. ",
  "dn17:1.16.2": "Vị ấy có được thiên nhãn là quả của nghiệp, nhờ đó thấy được kho báu có chủ lẫn không có chủ. ",
  "dn17:1.16.3": "Vị ấy đi đến vua Mahāsudassana và thưa: ",
  "dn17:1.16.4": "‘Xin đại vương hãy yên tâm, tôi sẽ lo việc tài sản cho đại vương bằng tài sản.’ ",
  "dn17:1.16.5": "Thuở xưa, này Ānanda, để thử gia chủ báu ấy, vua Mahāsudassana đã lên thuyền ra giữa dòng sông Hằng, rồi nói với gia chủ báu: ",
  "dn17:1.16.6": "‘Này gia chủ, ta cần vàng bạc.’ ",
  "dn17:1.16.7": "‘Thưa đại vương, vậy hãy cho thuyền cập vào một bờ.’ ",
  "dn17:1.16.8": "‘Ta cần vàng bạc ngay tại đây, này gia chủ.’ ",
  "dn17:1.16.9": "Rồi này Ānanda, gia chủ báu ấy thọc hai tay xuống nước và vớt lên một bình đầy vàng bạc, rồi thưa với vua Mahāsudassana: ",
  "dn17:1.16.10": "‘Chừng này là đủ chăng, thưa đại vương, chừng này đã làm xong chăng, thưa đại vương, chừng này đã dâng đủ chăng, thưa đại vương?’ ",
  "dn17:1.16.11": "Vua Mahāsudassana nói: ",
  "dn17:1.16.12": "‘Chừng này là đủ, này gia chủ, chừng này đã làm xong, này gia chủ, chừng này đã dâng đủ, này gia chủ.’ ",
  "dn17:1.16.13": "Này Ānanda, vua Mahāsudassana đã có một gia chủ báu như vậy. ",
  "dn17:1.17.0": "2.7. Tướng quân báu ",
  "dn17:1.18.1": "Lại nữa, này Ānanda, vua Mahāsudassana có một tướng quân báu hiện ra, ",
  "dn17:1.18.2": "là bậc trí, thông thạo, có trí tuệ, có khả năng khuyên vua Mahāsudassana đi đến nơi nên đi, rời khỏi nơi nên rời, ở lại nơi nên ở. ",
  "dn17:1.18.3": "Vị ấy đi đến vua Mahāsudassana và thưa: ",
  "dn17:1.18.4": "‘Xin đại vương hãy yên tâm, tôi sẽ chỉ dẫn.’ ",
  "dn17:1.18.5": "Này Ānanda, vua Mahāsudassana đã có một tướng quân báu như vậy. ",
  "dn17:1.18.6": "Này Ānanda, vua Mahāsudassana đầy đủ bảy báu này. ",
  "dn17:1.18.7.0": "3. Đầy đủ bốn thần lực ",
  "dn17:1.18.8": "Này Ānanda, vua Mahāsudassana đầy đủ bốn thần lực. ",
  "dn17:1.18.9": "Bốn thần lực ấy là gì? ",
  "dn17:1.18.10": "Này Ānanda, ở đây vua Mahāsudassana đẹp trai, dễ nhìn, khả ái, có dung sắc cao quý tuyệt hảo, vượt xa những người khác. ",
  "dn17:1.18.11": "Này Ānanda, vua Mahāsudassana đầy đủ thần lực thứ nhất này. ",
  "dn17:1.19.1": "Lại nữa, này Ānanda, vua Mahāsudassana có tuổi thọ dài, sống lâu, vượt xa những người khác. ",
  "dn17:1.19.2": "Này Ānanda, vua Mahāsudassana đầy đủ thần lực thứ hai này. ",
  "dn17:1.20.1": "Lại nữa, này Ānanda, vua Mahāsudassana ít bệnh, ít đau, có tiêu hóa điều hòa, không quá lạnh, không quá nóng, vượt xa những người khác. ",
  "dn17:1.20.2": "Này Ānanda, vua Mahāsudassana đầy đủ thần lực thứ ba này. ",
  "dn17:1.21.1": "Lại nữa, này Ānanda, vua Mahāsudassana được các Bà-la-môn và gia chủ yêu thương, quý mến. ",
  "dn17:1.21.2": "Ví như, này Ānanda, cha yêu thương, quý mến các con; ",
  "dn17:1.21.3": "cũng vậy, này Ānanda, vua Mahāsudassana được các Bà-la-môn và gia chủ yêu thương, quý mến. ",
  "dn17:1.21.4": "Này Ānanda, vua Mahāsudassana cũng yêu thương, quý mến các Bà-la-môn và gia chủ. ",
  "dn17:1.21.5": "Ví như, này Ānanda, cha yêu thương, quý mến các con; ",
  "dn17:1.21.6": "cũng vậy, này Ānanda, vua Mahāsudassana cũng yêu thương, quý mến các Bà-la-môn và gia chủ. ",
  "dn17:1.21.7": "Thuở xưa, này Ānanda, vua Mahāsudassana cùng bốn loại quân đi ra vườn ngự uyển. ",
  "dn17:1.21.8": "Rồi này Ānanda, các Bà-la-môn và gia chủ đến gặp vua Mahāsudassana và thưa rằng: ",
  "dn17:1.21.9": "‘Xin đại vương đi chậm lại, để chúng tôi được nhìn thấy đại vương lâu hơn.’ ",
  "dn17:1.21.10": "Này Ānanda, vua Mahāsudassana gọi người đánh xe: ",
  "dn17:1.21.11": "‘Này bạn đánh xe, hãy cho xe đi chậm lại, để ta được nhìn thấy các Bà-la-môn và gia chủ lâu hơn.’ ",
  "dn17:1.21.12": "Này Ānanda, vua Mahāsudassana đầy đủ thần lực thứ tư này. ",
  "dn17:1.21.13": "Này Ānanda, vua Mahāsudassana đầy đủ bốn thần lực này. ",
  "dn17:1.22.0": "4. Hồ sen cung điện Dhamma ",
  "dn17:1.22.1": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:1.22.2": "‘Vậy ta hãy xây các hồ sen giữa các hàng cây tāla này, cách nhau mỗi trăm cung.’ ",
  "dn17:1.22.3": "Này Ānanda, vua Mahāsudassana đã xây các hồ sen giữa các hàng cây tāla ấy, cách nhau mỗi trăm cung. ",
  "dn17:1.22.4": "Này Ānanda, các hồ sen ấy được lát bằng gạch bốn loại màu—",
  "dn17:1.22.5": "một viên gạch bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.22.6": "Này Ānanda, tại các hồ sen ấy có bốn bậc thang bốn loại màu. ",
  "dn17:1.22.7": "Một bậc thang bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.22.8": "Bậc thang bằng vàng có trụ bằng vàng, thanh chắn và viền trên bằng bạc. ",
  "dn17:1.22.9": "Bậc thang bằng bạc có trụ bằng bạc, thanh chắn và viền trên bằng vàng. ",
  "dn17:1.22.10": "Bậc thang bằng ngọc lưu ly có trụ bằng ngọc lưu ly, thanh chắn và viền trên bằng pha lê. ",
  "dn17:1.22.11": "Bậc thang bằng pha lê có trụ bằng pha lê, thanh chắn và viền trên bằng ngọc lưu ly. ",
  "dn17:1.22.12": "Này Ānanda, các hồ sen ấy được bao quanh bởi hai hàng lan can, một hàng bằng vàng, một hàng bằng bạc. ",
  "dn17:1.22.13": "Hàng lan can bằng vàng có trụ bằng vàng, thanh chắn và viền trên bằng bạc. ",
  "dn17:1.22.14": "Hàng lan can bằng bạc có trụ bằng bạc, thanh chắn và viền trên bằng vàng. ",
  "dn17:1.23.1": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:1.23.2": "‘Vậy ta hãy cho trồng các loại hoa sau đây trong các hồ sen này: sen xanh, sen đỏ, sen trắng, sen trắng lớn, nở quanh năm, cho tất cả mọi người không bị ngăn trở.’ ",
  "dn17:1.23.3": "Này Ānanda, vua Mahāsudassana đã cho trồng các loại hoa như vậy trong các hồ sen ấy: sen xanh, sen đỏ, sen trắng, sen trắng lớn, nở quanh năm, cho tất cả mọi người không bị ngăn trở. ",
  "dn17:1.23.4": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:1.23.5": "‘Vậy ta hãy đặt những người tắm gội bên bờ các hồ sen này, để họ tắm gội cho những người đến.’ ",
  "dn17:1.23.6": "Này Ānanda, vua Mahāsudassana đã đặt những người tắm gội bên bờ các hồ sen ấy, để họ tắm gội cho những người đến. ",
  "dn17:1.23.7": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:1.23.8": "‘Vậy ta hãy thiết lập sự bố thí bên bờ các hồ sen này—",
  "dn17:1.23.9": "cho đồ ăn cho người cần đồ ăn, cho thức uống cho người cần thức uống, cho y phục cho người cần y phục, cho xe cộ cho người cần xe cộ, cho giường nằm cho người cần giường nằm, cho phụ nữ cho người cần phụ nữ, cho bạc cho người cần bạc, cho vàng cho người cần vàng.’ ",
  "dn17:1.23.10": "Này Ānanda, vua Mahāsudassana đã thiết lập sự bố thí bên bờ các hồ sen ấy—",
  "dn17:1.23.11": "cho đồ ăn cho người cần đồ ăn, cho thức uống cho người cần thức uống, cho y phục cho người cần y phục, cho xe cộ cho người cần xe cộ, cho giường nằm cho người cần giường nằm, cho phụ nữ cho người cần phụ nữ, cho bạc cho người cần bạc, cho vàng cho người cần vàng. ",
  "dn17:1.24.1": "Rồi này Ānanda, các Bà-la-môn và gia chủ mang theo nhiều tài sản đi đến vua Mahāsudassana và thưa rằng: ",
  "dn17:1.24.2": "‘Thưa đại vương, nhiều tài sản này chúng tôi mang đến để dâng lên đại vương, xin đại vương hãy nhận lấy.’ ",
  "dn17:1.24.3": "‘Thôi, các ông, đủ rồi, ta cũng đã có nhiều tài sản được tạo ra bằng thuế hợp pháp; các tài sản ấy là của các ông, và hãy đem về thêm nữa từ ta.’ ",
  "dn17:1.24.4": "Họ bị vua từ chối, đi qua một bên và cùng suy nghĩ rằng: ",
  "dn17:1.24.5": "‘Đem những tài sản này trở về nhà thì thật không thích hợp cho chúng ta. ",
  "dn17:1.24.6": "Vậy chúng ta hãy xây cung điện cho vua Mahāsudassana.’ ",
  "dn17:1.24.7": "Họ đi đến vua Mahāsudassana và thưa rằng: ",
  "dn17:1.24.8": "‘Thưa đại vương, chúng tôi xin xây cung điện cho đại vương.’ ",
  "dn17:1.24.9": "Này Ānanda, vua Mahāsudassana im lặng nhận lời. ",
  "dn17:1.25.1": "Rồi này Ānanda, vua trời Đế Thích biết được suy nghĩ trong tâm của vua Mahāsudassana, bèn gọi Thiên tử Vissakamma: ",
  "dn17:1.25.2": "‘Này bạn Vissakamma, hãy đến và xây cho vua Mahāsudassana một cung điện tên là Dhamma.’ ",
  "dn17:1.25.3": "‘Thưa vâng, tôn giả’, này Ānanda, Thiên tử Vissakamma vâng lời vua trời Đế Thích, ví như một người lực sĩ co duỗi cánh tay, hay duỗi co cánh tay; cũng vậy—biến mất khỏi cõi Ba Mươi Ba và xuất hiện trước mặt vua Mahāsudassana. ",
  "dn17:1.25.4": "Rồi này Ānanda, Thiên tử Vissakamma nói với vua Mahāsudassana: ",
  "dn17:1.25.5": "‘Thưa đại vương, tôi xin xây cho đại vương cung điện tên là Dhamma.’ ",
  "dn17:1.25.6": "Này Ānanda, vua Mahāsudassana im lặng nhận lời. ",
  "dn17:1.25.7": "Rồi này Ānanda, Thiên tử Vissakamma xây cho vua Mahāsudassana cung điện tên là Dhamma. ",
  "dn17:1.25.8": "Này Ānanda, cung điện Dhamma từ đông sang tây dài một do-tuần, từ bắc xuống nam rộng nửa do-tuần. ",
  "dn17:1.25.9": "Này Ānanda, nền móng của cung điện Dhamma cao ba tầm người, được lát gạch bốn loại màu—",
  "dn17:1.25.10": "một viên gạch bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.26.1": "Này Ānanda, cung điện Dhamma có tám mươi bốn ngàn cây cột bốn loại màu—",
  "dn17:1.26.2": "một cột bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.26.3": "Này Ānanda, cung điện Dhamma được lát nền bằng các tấm ván bốn loại màu—",
  "dn17:1.26.4": "một tấm ván bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.26.5": "Này Ānanda, cung điện Dhamma có hai mươi bốn bậc thang bốn loại màu—",
  "dn17:1.26.6": "một bậc thang bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.26.7": "Bậc thang bằng vàng có trụ bằng vàng, thanh chắn và viền trên bằng bạc. ",
  "dn17:1.26.8": "Bậc thang bằng bạc có trụ bằng bạc, thanh chắn và viền trên bằng vàng. ",
  "dn17:1.26.9": "Bậc thang bằng ngọc lưu ly có trụ bằng ngọc lưu ly, thanh chắn và viền trên bằng pha lê. ",
  "dn17:1.26.10": "Bậc thang bằng pha lê có trụ bằng pha lê, thanh chắn và viền trên bằng ngọc lưu ly. ",
  "dn17:1.26.11": "Này Ānanda, ở cung điện Dhamma có tám mươi bốn ngàn phòng đỉnh bốn loại màu—",
  "dn17:1.26.12": "một phòng đỉnh bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.26.13": "Trong phòng đỉnh bằng vàng có giường bằng bạc, trong phòng đỉnh bằng bạc có giường bằng vàng, trong phòng đỉnh bằng ngọc lưu ly có giường bằng ngà, trong phòng đỉnh bằng pha lê có giường bằng gỗ quý. ",
  "dn17:1.26.14": "Ở cửa phòng đỉnh bằng vàng dựng một cây tāla bằng bạc, thân cây bằng bạc, lá và trái bằng vàng. ",
  "dn17:1.26.15": "Ở cửa phòng đỉnh bằng bạc dựng một cây tāla bằng vàng, thân cây bằng vàng, lá và trái bằng bạc. ",
  "dn17:1.26.16": "Ở cửa phòng đỉnh bằng ngọc lưu ly dựng một cây tāla bằng pha lê, thân cây bằng pha lê, lá và trái bằng ngọc lưu ly. ",
  "dn17:1.26.17": "Ở cửa phòng đỉnh bằng pha lê dựng một cây tāla bằng ngọc lưu ly, thân cây bằng ngọc lưu ly, lá và trái bằng pha lê. ",
  "dn17:1.27.1": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:1.27.2": "‘Vậy ta hãy xây một rừng cây tāla toàn bằng vàng ở trước cửa phòng đỉnh Mahāvyūha, nơi ta sẽ ngồi nghỉ ban ngày.’ ",
  "dn17:1.27.3": "Này Ānanda, vua Mahāsudassana đã xây một rừng cây tāla toàn bằng vàng ở trước cửa phòng đỉnh Mahāvyūha, nơi vua ngồi nghỉ ban ngày. ",
  "dn17:1.28.1": "Này Ānanda, cung điện Dhamma được bao quanh bởi hai hàng lan can, một hàng bằng vàng, một hàng bằng bạc. ",
  "dn17:1.28.2": "Hàng lan can bằng vàng có trụ bằng vàng, thanh chắn và viền trên bằng bạc. ",
  "dn17:1.28.3": "Hàng lan can bằng bạc có trụ bằng bạc, thanh chắn và viền trên bằng vàng. ",
  "dn17:1.29.1": "Này Ānanda, cung điện Dhamma được bao quanh bởi hai hàng lưới chuông—",
  "dn17:1.29.2": "một hàng lưới bằng vàng, một hàng lưới bằng bạc. ",
  "dn17:1.29.3": "Trên hàng lưới bằng vàng có các chuông bằng bạc, trên hàng lưới bằng bạc có các chuông bằng vàng. ",
  "dn17:1.29.4": "Này Ānanda, khi các hàng lưới chuông ấy bị gió lay động, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc. ",
  "dn17:1.29.5": "Ví như, này Ānanda, một bản nhạc có năm loại nhạc cụ, được khéo tập dượt, khéo đánh nhịp, được các nhạc công thiện nghệ cùng biểu diễn, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc; ",
  "dn17:1.29.6": "cũng vậy, này Ānanda, khi các hàng lưới chuông ấy bị gió lay động, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc. ",
  "dn17:1.29.7": "Này Ānanda, vào lúc bấy giờ, những kẻ ăn chơi, phóng túng, nghiện ngập trong kinh đô Kusāvatī, đã thưởng thức âm thanh của các hàng lưới chuông ấy khi bị gió lay động. ",
  "dn17:1.29.8": "Này Ānanda, khi cung điện Dhamma đã được xây xong, người ta khó nhìn thấy nó, vì nó làm chóa mắt. ",
  "dn17:1.29.9": "Ví như, này Ānanda, vào tháng cuối của mùa mưa, vào mùa thu, khi trời trong sạch không mây, mặt trời lên trên bầu trời, khó nhìn thấy vì làm chóa mắt; ",
  "dn17:1.29.10": "cũng vậy, này Ānanda, cung điện Dhamma khó nhìn thấy vì làm chóa mắt. ",
  "dn17:1.30.1": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:1.30.2": "‘Vậy ta hãy xây một hồ sen tên là Dhamma ở trước cung điện Dhamma.’ ",
  "dn17:1.30.3": "Này Ānanda, vua Mahāsudassana đã xây hồ sen tên là Dhamma ở trước cung điện Dhamma. ",
  "dn17:1.30.4": "Này Ānanda, hồ sen Dhamma từ đông sang tây dài một do-tuần, từ bắc xuống nam rộng nửa do-tuần. ",
  "dn17:1.30.5": "Này Ānanda, hồ sen Dhamma được lát bằng gạch bốn loại màu—",
  "dn17:1.30.6": "một viên gạch bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.31.1": "Này Ānanda, hồ sen Dhamma có hai mươi bốn bậc thang bốn loại màu—",
  "dn17:1.31.2": "một bậc thang bằng vàng, một bằng bạc, một bằng ngọc lưu ly, một bằng pha lê. ",
  "dn17:1.31.3": "Bậc thang bằng vàng có trụ bằng vàng, thanh chắn và viền trên bằng bạc. ",
  "dn17:1.31.4": "Bậc thang bằng bạc có trụ bằng bạc, thanh chắn và viền trên bằng vàng. ",
  "dn17:1.31.5": "Bậc thang bằng ngọc lưu ly có trụ bằng ngọc lưu ly, thanh chắn và viền trên bằng pha lê. ",
  "dn17:1.31.6": "Bậc thang bằng pha lê có trụ bằng pha lê, thanh chắn và viền trên bằng ngọc lưu ly. ",
  "dn17:1.31.7": "Này Ānanda, hồ sen Dhamma được bao quanh bởi hai hàng lan can—một hàng bằng vàng, một hàng bằng bạc. ",
  "dn17:1.31.8": "Hàng lan can bằng vàng có trụ bằng vàng, thanh chắn và viền trên bằng bạc. ",
  "dn17:1.31.9": "Hàng lan can bằng bạc có trụ bằng bạc, thanh chắn và viền trên bằng vàng. ",
  "dn17:1.32.1": "Này Ānanda, hồ sen Dhamma được bao quanh bởi bảy hàng cây tāla—",
  "dn17:1.32.2": "một hàng bằng vàng, một hàng bằng bạc, một hàng bằng ngọc lưu ly, một hàng bằng pha lê, một hàng bằng ngọc đỏ, một hàng bằng ngọc mắt mèo, một hàng bằng tất cả các loại báu. ",
  "dn17:1.32.3": "Cây tāla bằng vàng có thân bằng vàng, lá và trái bằng bạc. ",
  "dn17:1.32.4": "Cây tāla bằng bạc có thân bằng bạc, lá và trái bằng vàng. ",
  "dn17:1.32.5": "Cây tāla bằng ngọc lưu ly có thân bằng ngọc lưu ly, lá và trái bằng pha lê. ",
  "dn17:1.32.6": "Cây tāla bằng pha lê có thân bằng pha lê, lá và trái bằng ngọc lưu ly. ",
  "dn17:1.32.7": "Cây tāla bằng ngọc đỏ có thân bằng ngọc đỏ, lá và trái bằng ngọc mắt mèo. ",
  "dn17:1.32.8": "Cây tāla bằng ngọc mắt mèo có thân bằng ngọc mắt mèo, lá và trái bằng ngọc đỏ. ",
  "dn17:1.32.9": "Cây tāla bằng tất cả các loại báu có thân bằng tất cả các loại báu, lá và trái cũng bằng tất cả các loại báu. ",
  "dn17:1.32.10": "Này Ānanda, khi các hàng cây tāla ấy bị gió lay động, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc. ",
  "dn17:1.32.11": "Ví như, này Ānanda, một bản nhạc có năm loại nhạc cụ, được khéo tập dượt, khéo đánh nhịp, được các nhạc công thiện nghệ cùng biểu diễn, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc; ",
  "dn17:1.32.12": "cũng vậy, này Ānanda, khi các hàng cây tāla ấy bị gió lay động, phát ra âm thanh khả ái, dễ chịu, êm đềm và mê hoặc. ",
  "dn17:1.32.13": "Này Ānanda, vào lúc bấy giờ, những kẻ ăn chơi, phóng túng, nghiện ngập trong kinh đô Kusāvatī, đã thưởng thức âm thanh của các hàng cây tāla ấy khi bị gió lay động. ",
  "dn17:1.33.1": "Này Ānanda, khi cung điện Dhamma đã được xây xong và hồ sen Dhamma đã được làm xong, vua Mahāsudassana sau khi đã làm thỏa mãn các vị ‘được xem là Sa-môn trong số các Sa-môn, hay được xem là Bà-la-môn trong số các Bà-la-môn’ với mọi dục lạc, bèn bước lên cung điện Dhamma. ",
  "dn17:1.33.2": "Hết tụng phần thứ nhất. ",
  "dn17:2.1.0": "5. Sự chứng đắc thiền ",
  "dn17:2.1.1": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:2.1.2": "‘Đây là quả của nghiệp nào, kết quả của nghiệp nào mà nay ta có được đại thần lực, đại oai lực như vậy?’ ",
  "dn17:2.1.3": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:2.1.4": "‘Đây là quả của ba nghiệp, kết quả của ba nghiệp mà nay ta có được đại thần lực, đại oai lực như vậy, đó là—",
  "dn17:2.1.5": "bố thí, tự chế, chế ngự.’ ",
  "dn17:2.2.1": "Rồi này Ānanda, vua Mahāsudassana đi đến phòng đỉnh Mahāvyūha; sau khi đến, đứng ở cửa phòng đỉnh Mahāvyūha, vua nói lên lời cảm thán: ",
  "dn17:2.2.2": "‘Hỡi dục tầm, hãy dừng lại; hỡi sân tầm, hãy dừng lại; hỡi hại tầm, hãy dừng lại. ",
  "dn17:2.2.3": "Đến đây thôi, hỡi dục tầm, đến đây thôi, hỡi sân tầm, đến đây thôi, hỡi hại tầm.’ ",
  "dn17:2.3.1": "Rồi này Ānanda, vua Mahāsudassana vào phòng đỉnh Mahāvyūha, ngồi trên giường bằng vàng, ly dục, ly các pháp bất thiện, chứng đạt và an trú Thiền thứ nhất, có tầm, có tứ, có hỷ và lạc do ly dục sinh. ",
  "dn17:2.3.2": "Do tầm và tứ vắng lặng, vua chứng đạt và an trú Thiền thứ hai, có nội tâm yên tĩnh, có nhất tâm, không tầm, không tứ, có hỷ và lạc do định sinh. ",
  "dn17:2.3.3": "Do hỷ không còn, vua trú xả, có chánh niệm tỉnh giác, cảm nhận lạc bằng thân; đó là điều mà các bậc thánh gọi là: ‘xả, niệm, lạc trú’, vua chứng đạt và an trú Thiền thứ ba. ",
  "dn17:2.3.4": "Do đoạn tận lạc và đoạn tận khổ, trước đã diệt hỷ và ưu, vua chứng đạt và an trú Thiền thứ tư, không khổ không lạc, xả niệm thanh tịnh. ",
  "dn17:2.4.1": "Rồi này Ānanda, vua Mahāsudassana đi ra khỏi phòng đỉnh Mahāvyūha, vào phòng đỉnh bằng vàng, ngồi trên giường bằng bạc, ",
  "dn17:2.4.2": "an trú, biến mãn một phương với tâm câu hữu với từ. Cũng vậy với phương thứ hai, phương thứ ba, phương thứ tư. Như vậy, cùng khắp trên, dưới, ngang, và ở mọi nơi, đối với tất cả, cũng như đối với chính mình, vua an trú, biến mãn khắp thế giới với tâm câu hữu với từ, rộng lớn, quảng đại, vô lượng, không thù hận, không sân hận. ",
  "dn17:2.4.3": "Với tâm câu hữu với bi …(v.v.)… ",
  "dn17:2.4.4": "với tâm câu hữu với hỷ …(v.v.)… ",
  "dn17:2.4.5": "với tâm câu hữu với xả, an trú, biến mãn một phương. Cũng vậy với phương thứ hai, phương thứ ba, phương thứ tư. Như vậy, cùng khắp trên, dưới, ngang, và ở mọi nơi, đối với tất cả, cũng như đối với chính mình, vua an trú, biến mãn khắp thế giới với tâm câu hữu với xả, rộng lớn, quảng đại, vô lượng, không thù hận, không sân hận. ",
  "dn17:2.5.0": "6. Tám mươi bốn ngàn thành phố v.v. ",
  "dn17:2.5.1": "Này Ānanda, vua Mahāsudassana có tám mươi bốn ngàn thành phố, đứng đầu là kinh đô Kusāvatī; ",
  "dn17:2.5.2": "có tám mươi bốn ngàn cung điện, đứng đầu là cung điện Dhamma; ",
  "dn17:2.5.3": "có tám mươi bốn ngàn phòng đỉnh, đứng đầu là phòng đỉnh Mahāvyūha; ",
  "dn17:2.5.4": "có tám mươi bốn ngàn giường nằm bằng vàng, bằng bạc, bằng ngà, bằng gỗ quý, trải thảm lông dài, trải thảm trắng, trải thảm thêu, trải da sơn dương thượng hạng, có mái che, có gối đỏ ở hai đầu; ",
  "dn17:2.5.5": "có tám mươi bốn ngàn voi trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là tượng vương Uposatha; ",
  "dn17:2.5.6": "có tám mươi bốn ngàn ngựa trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là mã vương Valāhaka; ",
  "dn17:2.5.7": "có tám mươi bốn ngàn xe được phủ bằng da sư tử, da cọp, da báo, trùm bằng vải len vàng, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là xe Vejayanta; ",
  "dn17:2.5.8": "có tám mươi bốn ngàn viên ngọc, đứng đầu là ngọc báu; ",
  "dn17:2.5.9": "có tám mươi bốn ngàn phụ nữ, đứng đầu là hoàng hậu Subhaddā; ",
  "dn17:2.5.10": "có tám mươi bốn ngàn gia chủ, đứng đầu là gia chủ báu; ",
  "dn17:2.5.11": "có tám mươi bốn ngàn Sát-đế-lỵ chư hầu, đứng đầu là tướng quân báu; ",
  "dn17:2.5.12": "có tám mươi bốn ngàn con bò sữa cho sữa dồi dào, vắt vào chậu đồng; ",
  "dn17:2.5.13": "có tám mươi bốn ngàn vạn bộ y phục bằng vải lanh mịn, bằng vải bông mịn, bằng lụa mịn, bằng len mịn; ",
  "dn17:2.5.14": "này Ānanda, vua Mahāsudassana có tám mươi bốn ngàn bát vàng được dâng đồ ăn sáng và tối. ",
  "dn17:2.6.1": "Này Ānanda, vào lúc bấy giờ, tám mươi bốn ngàn voi đến hầu vua Mahāsudassana sáng và tối. ",
  "dn17:2.6.2": "Rồi này Ānanda, vua Mahāsudassana khởi lên ý nghĩ: ",
  "dn17:2.6.3": "‘Tám mươi bốn ngàn voi này đến hầu ta sáng và tối, vậy cứ mỗi trăm năm, bốn mươi hai ngàn voi đến hầu một lần.’ ",
  "dn17:2.6.4": "Rồi này Ānanda, vua Mahāsudassana gọi tướng quân báu: ",
  "dn17:2.6.5": "‘Này bạn tướng quân báu, tám mươi bốn ngàn voi này đến hầu ta sáng và tối; vậy này bạn tướng quân báu, cứ mỗi trăm năm, hãy cho bốn mươi hai ngàn voi đến hầu một lần.’ ",
  "dn17:2.6.6": "‘Thưa vâng, đại vương’, này Ānanda, tướng quân báu vâng lời vua Mahāsudassana. ",
  "dn17:2.6.7": "Rồi này Ānanda, về sau, cứ mỗi trăm năm, bốn mươi hai ngàn voi đến hầu vua Mahāsudassana một lần. ",
  "dn17:2.7.0": "7. Hoàng hậu Subhaddā đến thăm ",
  "dn17:2.7.1": "Rồi này Ānanda, sau nhiều năm, nhiều trăm năm, nhiều ngàn năm, hoàng hậu Subhaddā khởi lên ý nghĩ: ",
  "dn17:2.7.2": "‘Đã lâu ta không gặp vua Mahāsudassana. Vậy ta hãy đi thăm vua Mahāsudassana.’ ",
  "dn17:2.7.3": "Rồi này Ānanda, hoàng hậu Subhaddā gọi đoàn cung nữ: ",
  "dn17:2.7.4": "‘Hãy đến, các người gội đầu, mặc y phục vàng. ",
  "dn17:2.7.5": "Đã lâu chúng ta không gặp vua Mahāsudassana, chúng ta sẽ đi thăm vua Mahāsudassana.’ ",
  "dn17:2.7.6": "‘Thưa vâng, hoàng hậu’, này Ānanda, đoàn cung nữ vâng lời hoàng hậu Subhaddā, gội đầu, mặc y phục vàng rồi đi đến chỗ hoàng hậu Subhaddā. ",
  "dn17:2.8.1": "Rồi này Ānanda, hoàng hậu Subhaddā gọi tướng quân báu: ",
  "dn17:2.8.2": "‘Này bạn tướng quân báu, hãy chỉnh đốn bốn loại quân, đã lâu chúng ta không gặp vua Mahāsudassana, chúng ta sẽ đi thăm vua Mahāsudassana.’ ",
  "dn17:2.8.3": "‘Thưa vâng, hoàng hậu’, này Ānanda, tướng quân báu vâng lời hoàng hậu Subhaddā, sau khi chỉnh đốn bốn loại quân, báo cho hoàng hậu Subhaddā: ",
  "dn17:2.8.4": "‘Thưa hoàng hậu, bốn loại quân đã được chỉnh đốn, ",
  "dn17:2.8.5": "xin hoàng hậu định giờ nào.’ ",
  "dn17:2.8.6": "Rồi này Ānanda, hoàng hậu Subhaddā cùng với bốn loại quân và đoàn cung nữ đi đến cung điện Dhamma; sau khi đến, bà bước lên cung điện Dhamma, đi đến phòng đỉnh Mahāvyūha. ",
  "dn17:2.8.7": "Đến nơi, bà đứng dựa vào cửa phòng đỉnh Mahāvyūha. ",
  "dn17:2.8.8": "Rồi này Ānanda, vua Mahāsudassana nghe tiếng động: ",
  "dn17:2.8.9": "‘Tiếng gì như tiếng đại chúng?’ đi ra khỏi phòng đỉnh Mahāvyūha, thấy hoàng hậu Subhaddā đứng dựa vào cửa, thấy vậy bèn nói với hoàng hậu Subhaddā: ",
  "dn17:2.8.10": "‘Thưa hoàng hậu, xin hãy đứng ngay tại đây, đừng đi vào.’ ",
  "dn17:2.9.1": "Rồi này Ānanda, vua Mahāsudassana gọi một người: ",
  "dn17:2.9.2": "‘Hãy đến, này người kia, mang giường bằng vàng từ phòng đỉnh Mahāvyūha ra, sắp đặt trong rừng cây tāla toàn bằng vàng.’ ",
  "dn17:2.9.3": "‘Thưa vâng, đại vương’, này Ānanda, người ấy vâng lời vua Mahāsudassana, mang giường bằng vàng từ phòng đỉnh Mahāvyūha ra, sắp đặt trong rừng cây tāla toàn bằng vàng. ",
  "dn17:2.9.4": "Rồi này Ānanda, vua Mahāsudassana nằm xuống tư thế sư tử nằm, nghiêng về phía phải, chân đặt lên chân, có chánh niệm tỉnh giác. ",
  "dn17:2.10.1": "Rồi này Ānanda, hoàng hậu Subhaddā khởi lên ý nghĩ: ",
  "dn17:2.10.2": "‘Các căn của vua Mahāsudassana thật trong sáng, nước da thật trong sạch, tươi tỉnh; mong sao vua Mahāsudassana không qua đời’; bà nói với vua Mahāsudassana: ",
  "dn17:2.10.3": "‘Thưa đại vương, đây là tám mươi bốn ngàn thành phố của ngài, đứng đầu là kinh đô Kusāvatī. ",
  "dn17:2.10.4": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.5": "Thưa đại vương, đây là tám mươi bốn ngàn cung điện của ngài, đứng đầu là cung điện Dhamma. ",
  "dn17:2.10.6": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.7": "Thưa đại vương, đây là tám mươi bốn ngàn phòng đỉnh của ngài, đứng đầu là phòng đỉnh Mahāvyūha. ",
  "dn17:2.10.8": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.9": "Thưa đại vương, đây là tám mươi bốn ngàn giường nằm của ngài, bằng vàng, bằng bạc, bằng ngà, bằng gỗ quý, trải thảm lông dài, trải thảm trắng, trải thảm thêu, trải da sơn dương thượng hạng, có mái che, có gối đỏ ở hai đầu. ",
  "dn17:2.10.10": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.11": "Thưa đại vương, đây là tám mươi bốn ngàn voi của ngài, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là tượng vương Uposatha. ",
  "dn17:2.10.12": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.13": "Thưa đại vương, đây là tám mươi bốn ngàn ngựa của ngài, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là mã vương Valāhaka. ",
  "dn17:2.10.14": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.15": "Thưa đại vương, đây là tám mươi bốn ngàn xe của ngài, được phủ bằng da sư tử, da cọp, da báo, trùm bằng vải len vàng, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là xe Vejayanta. ",
  "dn17:2.10.16": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.17": "Thưa đại vương, đây là tám mươi bốn ngàn viên ngọc của ngài, đứng đầu là ngọc báu. ",
  "dn17:2.10.18": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.19": "Thưa đại vương, đây là tám mươi bốn ngàn phụ nữ của ngài, đứng đầu là nữ báu. ",
  "dn17:2.10.20": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.21": "Thưa đại vương, đây là tám mươi bốn ngàn gia chủ của ngài, đứng đầu là gia chủ báu. ",
  "dn17:2.10.22": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.23": "Thưa đại vương, đây là tám mươi bốn ngàn Sát-đế-lỵ chư hầu của ngài, đứng đầu là tướng quân báu. ",
  "dn17:2.10.24": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.25": "Thưa đại vương, đây là tám mươi bốn ngàn con bò sữa cho sữa dồi dào, vắt vào chậu đồng. ",
  "dn17:2.10.26": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.27": "Thưa đại vương, đây là tám mươi bốn ngàn vạn bộ y phục của ngài, bằng vải lanh mịn, bằng vải bông mịn, bằng lụa mịn, bằng len mịn. ",
  "dn17:2.10.28": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống. ",
  "dn17:2.10.29": "Thưa đại vương, đây là tám mươi bốn ngàn bát vàng của ngài được dâng đồ ăn sáng và tối. ",
  "dn17:2.10.30": "Xin đại vương hãy khởi tâm tha thiết, hãy gắn bó với cuộc sống.’ ",
  "dn17:2.11.1": "Khi được nói vậy, này Ānanda, vua Mahāsudassana nói với hoàng hậu Subhaddā: ",
  "dn17:2.11.2": "‘Thưa hoàng hậu, trước đây nàng đã đối xử với ta bằng lời khả lạc, đáng yêu, dễ thương, khả ái; ",
  "dn17:2.11.3": "thế mà giờ đây vào lúc cuối đời của ta, nàng lại đối xử với ta bằng lời không khả lạc, không đáng yêu, không dễ thương, không khả ái.’ ",
  "dn17:2.11.4": "‘Thưa đại vương, thiếp phải đối xử với ngài thế nào?’ ",
  "dn17:2.11.5": "‘Thưa hoàng hậu, nàng hãy đối xử với ta như thế này: ",
  "dn17:2.11.6": "“Thưa đại vương, tất cả những gì khả ái và dễ thương đều phải chia lìa, xa cách, trở nên khác đi; xin đại vương đừng qua đời với tâm còn luyến tiếc, qua đời với tâm luyến tiếc là khổ, qua đời với tâm luyến tiếc bị chê trách. ",
  "dn17:2.11.7": "Thưa đại vương, đây là tám mươi bốn ngàn thành phố của ngài, đứng đầu là kinh đô Kusāvatī. ",
  "dn17:2.11.8": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.9": "Thưa đại vương, đây là tám mươi bốn ngàn cung điện của ngài, đứng đầu là cung điện Dhamma. ",
  "dn17:2.11.10": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.11": "Thưa đại vương, đây là tám mươi bốn ngàn phòng đỉnh của ngài, đứng đầu là phòng đỉnh Mahāvyūha. ",
  "dn17:2.11.12": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.13": "Thưa đại vương, đây là tám mươi bốn ngàn giường nằm của ngài, bằng vàng, bằng bạc, bằng ngà, bằng gỗ quý, trải thảm lông dài, trải thảm trắng, trải thảm thêu, trải da sơn dương thượng hạng, có mái che, có gối đỏ ở hai đầu. ",
  "dn17:2.11.14": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.15": "Thưa đại vương, đây là tám mươi bốn ngàn voi của ngài, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là tượng vương Uposatha. ",
  "dn17:2.11.16": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.17": "Thưa đại vương, đây là tám mươi bốn ngàn ngựa của ngài, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là mã vương Valāhaka. ",
  "dn17:2.11.18": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.19": "Thưa đại vương, đây là tám mươi bốn ngàn xe của ngài, được phủ bằng da sư tử, da cọp, da báo, trùm bằng vải len vàng, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là xe Vejayanta. ",
  "dn17:2.11.20": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.21": "Thưa đại vương, đây là tám mươi bốn ngàn viên ngọc của ngài, đứng đầu là ngọc báu. ",
  "dn17:2.11.22": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.23": "Thưa đại vương, đây là tám mươi bốn ngàn phụ nữ của ngài, đứng đầu là hoàng hậu Subhaddā. ",
  "dn17:2.11.24": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.25": "Thưa đại vương, đây là tám mươi bốn ngàn gia chủ của ngài, đứng đầu là gia chủ báu. ",
  "dn17:2.11.26": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.27": "Thưa đại vương, đây là tám mươi bốn ngàn Sát-đế-lỵ chư hầu của ngài, đứng đầu là tướng quân báu. ",
  "dn17:2.11.28": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.29": "Thưa đại vương, đây là tám mươi bốn ngàn con bò sữa cho sữa dồi dào, vắt vào chậu đồng. ",
  "dn17:2.11.30": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.31": "Thưa đại vương, đây là tám mươi bốn ngàn vạn bộ y phục của ngài, bằng vải lanh mịn, bằng vải bông mịn, bằng lụa mịn, bằng len mịn. ",
  "dn17:2.11.32": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.11.33": "Thưa đại vương, đây là tám mươi bốn ngàn bát vàng của ngài được dâng đồ ăn sáng và tối. ",
  "dn17:2.11.34": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống.”’ ",
  "dn17:2.12.1": "Khi được nói vậy, này Ānanda, hoàng hậu Subhaddā khóc lóc, rơi lệ. ",
  "dn17:2.12.2": "Rồi này Ānanda, hoàng hậu Subhaddā lau nước mắt và nói với vua Mahāsudassana: ",
  "dn17:2.12.3": "‘Thưa đại vương, tất cả những gì khả ái và dễ thương đều phải chia lìa, xa cách, trở nên khác đi; xin đại vương đừng qua đời với tâm còn luyến tiếc, qua đời với tâm luyến tiếc là khổ, qua đời với tâm luyến tiếc bị chê trách. ",
  "dn17:2.12.4": "Thưa đại vương, đây là tám mươi bốn ngàn thành phố của ngài, đứng đầu là kinh đô Kusāvatī. ",
  "dn17:2.12.5": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.6": "Thưa đại vương, đây là tám mươi bốn ngàn cung điện của ngài, đứng đầu là cung điện Dhamma. ",
  "dn17:2.12.7": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.8": "Thưa đại vương, đây là tám mươi bốn ngàn phòng đỉnh của ngài, đứng đầu là phòng đỉnh Mahāvyūha. ",
  "dn17:2.12.9": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.10": "Thưa đại vương, đây là tám mươi bốn ngàn giường nằm của ngài, bằng vàng, bằng bạc, bằng ngà, bằng gỗ quý, trải thảm lông dài, trải thảm trắng, trải thảm thêu, trải da sơn dương thượng hạng, có mái che, có gối đỏ ở hai đầu. ",
  "dn17:2.12.11": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.12": "Thưa đại vương, đây là tám mươi bốn ngàn voi của ngài, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là tượng vương Uposatha. ",
  "dn17:2.12.13": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.14": "Thưa đại vương, đây là tám mươi bốn ngàn ngựa của ngài, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là mã vương Valāhaka. ",
  "dn17:2.12.15": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.16": "Thưa đại vương, đây là tám mươi bốn ngàn xe của ngài, được phủ bằng da sư tử, da cọp, da báo, trùm bằng vải len vàng, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là xe Vejayanta. ",
  "dn17:2.12.17": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.18": "Thưa đại vương, đây là tám mươi bốn ngàn viên ngọc của ngài, đứng đầu là ngọc báu. ",
  "dn17:2.12.19": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.20": "Thưa đại vương, đây là tám mươi bốn ngàn phụ nữ của ngài, đứng đầu là nữ báu. ",
  "dn17:2.12.21": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.22": "Thưa đại vương, đây là tám mươi bốn ngàn gia chủ của ngài, đứng đầu là gia chủ báu. ",
  "dn17:2.12.23": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.24": "Thưa đại vương, đây là tám mươi bốn ngàn Sát-đế-lỵ chư hầu của ngài, đứng đầu là tướng quân báu. ",
  "dn17:2.12.25": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.26": "Thưa đại vương, đây là tám mươi bốn ngàn con bò sữa cho sữa dồi dào, vắt vào chậu đồng. ",
  "dn17:2.12.27": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.28": "Thưa đại vương, đây là tám mươi bốn ngàn vạn bộ y phục của ngài, bằng vải lanh mịn, bằng vải bông mịn, bằng lụa mịn, bằng len mịn. ",
  "dn17:2.12.29": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống. ",
  "dn17:2.12.30": "Thưa đại vương, đây là tám mươi bốn ngàn bát vàng của ngài được dâng đồ ăn sáng và tối. ",
  "dn17:2.12.31": "Xin đại vương hãy từ bỏ lòng ham muốn đối với chúng, đừng gắn bó với cuộc sống.’ ",
  "dn17:2.13.0": "8. Sinh lên cõi Phạm thiên ",
  "dn17:2.13.1": "Rồi này Ānanda, không bao lâu sau vua Mahāsudassana qua đời. ",
  "dn17:2.13.2": "Ví như, này Ānanda, một gia chủ hay con của gia chủ sau khi ăn một bữa cơm ngon cảm thấy buồn ngủ; cũng vậy, này Ānanda, vua Mahāsudassana có cảm thọ lúc lâm chung. ",
  "dn17:2.13.3": "Này Ānanda, sau khi qua đời, vua Mahāsudassana được sinh vào thiện thú, cõi Phạm thiên. ",
  "dn17:2.13.4": "Này Ānanda, vua Mahāsudassana đã chơi đùa như một cậu bé trong tám mươi bốn ngàn năm. ",
  "dn17:2.13.5": "Làm phó vương trong tám mươi bốn ngàn năm. ",
  "dn17:2.13.6": "Trị vì trong tám mươi bốn ngàn năm. ",
  "dn17:2.13.7": "Trong tám mươi bốn ngàn năm, sống đời phạm hạnh tại cung điện Dhamma với tư cách gia chủ. ",
  "dn17:2.13.8": "Vị ấy sau khi tu tập bốn phạm trú, khi thân hoại mạng chung được sinh vào cõi Phạm thiên. ",
  "dn17:2.14.1": "Này Ānanda, có thể ông nghĩ rằng: ",
  "dn17:2.14.2": "‘Vua Mahāsudassana thời ấy hẳn là người khác.’ ",
  "dn17:2.14.3": "Nhưng, này Ānanda, không nên xem như vậy. Ta chính là vua Mahāsudassana thời ấy. ",
  "dn17:2.14.4": "Tám mươi bốn ngàn thành phố đứng đầu là kinh đô Kusāvatī là của ta; tám mươi bốn ngàn cung điện đứng đầu là cung điện Dhamma là của ta; tám mươi bốn ngàn phòng đỉnh đứng đầu là phòng đỉnh Mahāvyūha là của ta; tám mươi bốn ngàn giường nằm bằng vàng, bằng bạc, bằng ngà, bằng gỗ quý, trải thảm lông dài, trải thảm trắng, trải thảm thêu, trải da sơn dương thượng hạng, có mái che, có gối đỏ ở hai đầu là của ta; tám mươi bốn ngàn voi trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là tượng vương Uposatha là của ta; tám mươi bốn ngàn ngựa trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là mã vương Valāhaka là của ta; tám mươi bốn ngàn xe được phủ bằng da sư tử, da cọp, da báo, trùm bằng vải len vàng, trang sức vàng, mang cờ vàng, được phủ bằng lưới bằng vàng, đứng đầu là xe Vejayanta là của ta; tám mươi bốn ngàn viên ngọc đứng đầu là ngọc báu là của ta; tám mươi bốn ngàn phụ nữ đứng đầu là hoàng hậu Subhaddā là của ta; tám mươi bốn ngàn gia chủ đứng đầu là gia chủ báu là của ta; tám mươi bốn ngàn Sát-đế-lỵ chư hầu đứng đầu là tướng quân báu là của ta; tám mươi bốn ngàn con bò sữa cho sữa dồi dào, vắt vào chậu đồng là của ta; tám mươi bốn ngàn vạn bộ y phục bằng vải lanh mịn, bằng vải bông mịn, bằng lụa mịn, bằng len mịn là của ta; tám mươi bốn ngàn bát vàng được dâng đồ ăn sáng và tối là của ta. ",
  "dn17:2.15.1": "Này Ānanda, trong tám mươi bốn ngàn thành phố ấy, chỉ có một thành phố mà ta đã ở vào thời đó, đó là kinh đô Kusāvatī. ",
  "dn17:2.15.2": "Này Ānanda, trong tám mươi bốn ngàn cung điện ấy, chỉ có một cung điện mà ta đã ở vào thời đó, đó là cung điện Dhamma. ",
  "dn17:2.15.3": "Này Ānanda, trong tám mươi bốn ngàn phòng đỉnh ấy, chỉ có một phòng đỉnh mà ta đã ở vào thời đó, đó là phòng đỉnh Mahāvyūha. ",
  "dn17:2.15.4": "Này Ānanda, trong tám mươi bốn ngàn giường nằm ấy, chỉ có một giường nằm mà ta đã sử dụng vào thời đó, là bằng vàng, bằng bạc, bằng ngà, hoặc bằng gỗ quý. ",
  "dn17:2.15.5": "Này Ānanda, trong tám mươi bốn ngàn voi ấy, chỉ có một voi mà ta đã cưỡi vào thời đó, đó là tượng vương Uposatha. ",
  "dn17:2.15.6": "Này Ānanda, trong tám mươi bốn ngàn ngựa ấy, chỉ có một ngựa mà ta đã cưỡi vào thời đó, đó là mã vương Valāhaka. ",
  "dn17:2.15.7": "Này Ānanda, trong tám mươi bốn ngàn xe ấy, chỉ có một xe mà ta đã cưỡi vào thời đó, đó là xe Vejayanta. ",
  "dn17:2.15.8": "Này Ānanda, trong tám mươi bốn ngàn phụ nữ ấy, chỉ có một phụ nữ hầu hạ ta vào thời đó, hoặc là một nữ Sát-đế-lỵ, hoặc là một nữ thương gia. ",
  "dn17:2.15.9": "Này Ānanda, trong tám mươi bốn ngàn vạn bộ y phục ấy, chỉ có một bộ y phục mà ta đã mặc vào thời đó, hoặc bằng vải lanh mịn, hoặc bằng vải bông mịn, hoặc bằng lụa mịn, hoặc bằng len mịn. ",
  "dn17:2.15.10": "Này Ānanda, trong tám mươi bốn ngàn bát vàng ấy, chỉ có một bát mà ta đã ăn vào thời đó, nhiều nhất là một nāḷika cơm và đồ ăn đi kèm. ",
  "dn17:2.16.1": "Này Ānanda, hãy xem, tất cả các hành ấy đều đã qua, đã diệt, đã thay đổi. ",
  "dn17:2.16.2": "Này Ānanda, các hành là vô thường như vậy; ",
  "dn17:2.16.3": "này Ānanda, các hành là không kiên cố như vậy; ",
  "dn17:2.16.4": "này Ānanda, các hành là không đáng nương tựa như vậy. ",
  "dn17:2.16.5": "Đến mức độ này, này Ānanda, là đủ để nhàm chán đối với tất cả các hành, đủ để ly tham, đủ để giải thoát. ",
  "dn17:2.17.1": "Này Ānanda, Ta nhớ rằng đã sáu lần bỏ lại nhục thân ở nơi này, và khi ấy ta là Chuyển Luân Thánh Vương, đúng pháp, là vua pháp, bốn phương chiến thắng, đất nước an ổn, đầy đủ bảy báu; đây là lần thứ bảy bỏ lại nhục thân. ",
  "dn17:2.17.2": "Này Ānanda, trong thế giới với chư thiên, Ma vương, Phạm thiên, cùng các chúng Sa-môn, Bà-la-môn, trời và người, Ta không thấy một nơi nào mà Như Lai sẽ bỏ lại nhục thân lần thứ tám.” ",
  "dn17:2.17.3": "Thế Tôn đã nói như vậy. ",
  "dn17:2.17.4": "Sau khi nói xong, Đạo sư Thiện Thệ nói thêm bài kệ này: ",
  "dn17:2.17.5": "“Các hành quả là vô thường, ",
  "dn17:2.17.6": "Có pháp sinh rồi diệt; ",
  "dn17:2.17.7": "Sinh rồi thì lại diệt, ",
  "dn17:2.17.8": "Sự vắng lặng của chúng là an lạc.” ",
  "dn17:2.17.9": "Kinh Đại Thiện Kiến thứ tư đã kết thúc. "
}

